svg.script:
    let currentX = null;
    let laneOffset = 0;

    function animate() {

      const targetNode =
          document.getElementById("front_target_x");

      const speedNode =
          document.getElementById("ego_speed_value");

      const car =
          document.getElementById("front_car");

      const label =
          document.getElementById("front_label");

      const lane =
          document.getElementById("lane");

      /* voiture avant */

      if (targetNode && car) {

        const targetX =
            parseFloat(targetNode.textContent);

        if (!isNaN(targetX)) {

          if (currentX === null) {
            currentX = targetX;
          }

          currentX =
              currentX +
              (targetX - currentX) * 0.04;

          car.setAttribute("x", currentX);

          if (label) {
            label.setAttribute(
                "x",
                currentX + 50
            );
          }
        }
      }

      /* défilement route */

      if (speedNode && lane) {

        const speed =
            parseFloat(speedNode.textContent);

        if (!isNaN(speed)) {

          laneOffset =
              laneOffset +
              Math.max(
                  0.5,
                  speed * 0.1
              );

          lane.setAttribute(
              "stroke-dashoffset",
              laneOffset
          );
        }
      }

const accelNode =
    document.getElementById("accel_angle");

const needle =
    document.getElementById("accel_needle");

if (accelNode && needle) {

  const angle =
      parseFloat(accelNode.textContent);

  if (!isNaN(angle)) {

    const clamped =
        Math.max(-90, Math.min(90, angle));

    needle.setAttribute(
      "transform",
      "rotate(" + clamped + ")"
    );
  }
}

      requestAnimationFrame(animate);
    }


    requestAnimationFrame(animate);
